def get_skin_by_id(skin_id):
    for skin in SKINS_LIST:
        if skin['id'] == skin_id:
            return skin
    return SKINS_LIST[0]

def get_all_skins():
    return SKINS_LIST

def get_skins_by_category(categoria):
    resultado = []
    for skin in SKINS_LIST:
        if skin.get('categoria') == categoria:
            resultado.append(skin)
    return resultado
